// ── Variable lookup tables ─────────────────────────────────────────
const PARTICLE_SIZES  = {"Fireworks Regular":1,"Fireworks Tiny":0.1,"Fireworks Small":0.5,"Fireworks Medium":2,"Fireworks Large":4,"Ball Pit":10,"Lava Lamp":64};
const PULSATING_SIZES = {"Off":0,"Normal":0.5,"Large":1.5,"Obnoxious":3};
const TRAIL_LENGTHS   = {"Normal":20,"Absolute":0,"Very Strong":1,"Powerful":12,"Subtle":50,"None":250};
const VELOCITIES      = {"Normal":1,"Glacial Pace":0.15,"Slow":0.5,"Quick":2,"Fast":5,"Hyperspeed":16,"Starry Night":512,"Reverse":-0.5,"Super Reverse":-3,"None":0};
const GRAVITIES       = {"Normal":1,"Moon":0.1,"Zero G":0,"Heavy":2.5,"Very Heavy":5,"Upwards":-1,"Slow Rise":-0.15};
const MOUSE_GRAVITIES = {"Normal":1,"Low":0.5,"High":2,"Extreme":5,"Gravitron":32,"Black Hole":256,"Supermassive Black Hole":512,"Singularity":2048};
const DENSITIES       = {"Normal":8,"A Couple":2,"Plenty":16,"Lots":32,"Maximum":64};
const COMPLEXITIES    = {"Normal":8,"Few":2,"Plenty":16,"Lots":32,"Maximum":64};
const FW_WIDTHS       = {"Normal":1.5,"Short":0.5,"Squash":0.05,"Wide":5,"Landscape":25,"All":999};
const FW_HEIGHTS      = {"Normal":1.5,"Short":0.5,"Squash":0.05,"Tall":5,"Trees":25,"All":999};
const BG_PRESETS      = {"Black":[0,0,0],"White":[255,255,255],"Red":[155,20,20],"Green":[20,155,20],"Blue":[20,20,155]};

// ── State ──────────────────────────────────────────────────────────
let particles = [];
let colors = [];
let backgroundColor = {r:0, g:0, b:0};
let particleShape = 'circle';
let particleSize = 1;
let originalFireworkSize = 0;
let trailLength = 20;
let velocity = 1;
let gravity = 1;
let mouseGravityLevel = 1;
let density = 8;
let complexity = 8;
let fireworkWidth = 1.5;
let fireworkHeight = 1.5;
let upAndDownMode = false;
let maxFireworks = 50;
let mousePressTime = 0;
let velocityBoostEndTime = 0;

function setColors(pal) {
  const palettes = {
    default:   ['#F22222','#F28705','#FACECE','#3F5FFF','#F2CB05','#FFFFFF'],
    flat:      ['#F15A5A','#F0C419','#4EBA6F','#2D95BF','#955BA5','#FFFFFF'],
    neon:      ['#9500FF','#00E804','#001CFF','#FFFA0C','#FF00B2','#00ffff'],
    greyscale: ['#FFFFFF','#BFBFBF','#808080','#6E6E6E','#E6E6E6','#F7F7F7'],
    'b+w':     ['#FFFFFF','#000000'],
    lightning: ['#FFC54C','#FFF099','#FFAC00','#ffff00','#7F6326','#CC8A00'],
    water:     ['#3587F2','#2A6BBF','#6DB4F2','#0000ff','#C2F2ED','#00ffff'],
    fire:      ['#ff0000','#FF0600','#F25116','#F2D95C','#F2B544','#F28A2E'],
    earth:     ['#F6C977','#C09268','#FFF46F','#BDA488','#72341C','#7F7100'],
    pastel:    ['#FFC4C0','#FEE1BF','#F9FFBD','#DDFFBE','#BEFFFC','#D0D9F2','#FFFFFF'],
  };
  const hexes = palettes[pal] || palettes.default;
  colors = hexes.map(h => p.color(h));
}

function readVars() {
  setColors(p.getSynthVar('color_palette') || 'default');
  const bg = BG_PRESETS[p.getSynthVar('background')] || BG_PRESETS.Black;
  backgroundColor = {r: bg[0], g: bg[1], b: bg[2]};
  particleSize         = PARTICLE_SIZES[p.getSynthVar('particle_size')]   ?? 1;
  particleShape        = p.getSynthVar('particle_shape')                   || 'circle';
  originalFireworkSize = PULSATING_SIZES[p.getSynthVar('pulsating_star')] ?? 0;
  trailLength          = TRAIL_LENGTHS[p.getSynthVar('trail_length')]      ?? 20;
  velocity             = VELOCITIES[p.getSynthVar('velocity')]             ?? 1;
  gravity              = GRAVITIES[p.getSynthVar('gravity')]               ?? 1;
  mouseGravityLevel    = MOUSE_GRAVITIES[p.getSynthVar('mouse_gravity')]   ?? 1;
  density              = DENSITIES[p.getSynthVar('density')]               ?? 8;
  complexity           = COMPLEXITIES[p.getSynthVar('complexity')]         ?? 8;
  fireworkWidth        = FW_WIDTHS[p.getSynthVar('firework_width')]        ?? 1.5;
  fireworkHeight       = FW_HEIGHTS[p.getSynthVar('firework_height')]      ?? 1.5;
  upAndDownMode        = (p.getSynthVar('wavy_mode') || 'Off') === 'On';
}

// ── Classes ────────────────────────────────────────────────────────
class Spark {
  constructor(x, y, size, col) {
    this.x = x; this.y = y;
    this.size = size; this.col = col;
    this.angle = p.random(p.TWO_PI);
    this.speed = p.random(0.5, 2);
  }
  display() {
    p.noStroke();
    p.fill(this.col);
    switch (particleShape) {
      case 'square':
        p.rectMode(p.CENTER);
        p.rect(this.x, this.y, this.size, this.size);
        break;
      case 'triangle':
        p.push(); p.translate(this.x, this.y); p.rotate(this.angle);
        p.triangle(-this.size/2, this.size/2, 0, -this.size/2, this.size/2, this.size/2);
        p.pop();
        break;
      case 'star':
        p.push(); p.translate(this.x, this.y); p.rotate(this.angle);
        p.beginShape();
        for (let i = 0; i < 10; i++) {
          const r = i % 2 === 0 ? this.size/2 : this.size/4;
          p.vertex(r * p.cos((p.TWO_PI * i)/10), r * p.sin((p.TWO_PI * i)/10));
        }
        p.endShape(p.CLOSE);
        p.pop();
        break;
      default:
        p.ellipse(this.x, this.y, this.size);
    }
  }
  update() {
    const grav = upAndDownMode
      ? p.map(p.sin(p.frameCount * (p.TWO_PI / 120)), -1, 1, -1, 1)
      : gravity;
    const vel = (p.millis() < velocityBoostEndTime) ? velocity * mouseGravityLevel : velocity;
    this.x += p.cos(this.angle) * this.speed * vel;
    this.y += p.sin(this.angle) * this.speed * vel + grav;
    if (p.mouseIsPressed) {
      const d = p.createVector(p.mouseX - this.x, p.mouseY - this.y);
      d.normalize(); d.mult(mouseGravityLevel);
      this.x += d.x; this.y += d.y;
    }
  }
}

class Particle {
  constructor(x, y, size, col) {
    this.x = x; this.y = y; this.size = size; this.col = col;
    this.sparks = [];
    const count = p.random(5, 20) * density;
    for (let i = 0; i < count; i++) {
      const angle = p.random(p.TWO_PI);
      const dX = x + p.cos(angle) * p.random(size * 0.5, size * fireworkWidth);
      const dY = y + p.sin(angle) * p.random(size * 0.5, size * fireworkHeight);
      this.sparks.push(new Spark(dX, dY, p.random(1, size * 0.5), col));
    }
  }
  display() {
    for (const s of this.sparks) s.display();
    if (originalFireworkSize > 0) {
      p.noStroke();
      p.fill(this.col);
      const pulse = p.map(p.sin(p.frameCount * (p.TWO_PI / 120)), -1, 1, -1, 1);
      p.ellipse(this.x, this.y, this.size * originalFireworkSize * pulse);
    }
  }
  update() { for (const s of this.sparks) s.update(); }
}

function generateFirework() {
  const radius = p.random(2, 16) * particleSize;
  particles.push(new Particle(
    p.random(p.width), p.random(p.height),
    radius, colors[p.floor(p.random(colors.length))]
  ));
}

// ── Lifecycle ──────────────────────────────────────────────────────
p.setup = () => {
  p.createCanvas(400, 400);
  p.frameRate(30);
  readVars();
  for (let i = 0; i < complexity; i++) generateFirework();
};

p.draw = () => {
  p.background(backgroundColor.r, backgroundColor.g, backgroundColor.b, trailLength);
  for (const pt of particles) { pt.display(); pt.update(); }

  if (p.mouseIsPressed) {
    if (mousePressTime === 0) mousePressTime = p.millis();
  } else {
    if (mousePressTime !== 0 && p.millis() - mousePressTime > 3000)
      velocityBoostEndTime = p.millis() + 1000;
    mousePressTime = 0;
  }

  while (particles.length > maxFireworks) particles.shift();
};

p.mousePressed = () => {
  readVars();
  for (let i = 0; i < complexity; i++) generateFirework();
};
